    SIGSYS            = 22;
    SIGTERM           = 23;
    SIGTRAP           = 24;
    SIGTSTP           = 25;
    SIGTTIN           = 26;
    SIGTTOU           = 27;
    SIGURG            = 28;
    SIGUSR1           = 29;
    SIGUSR2           = 30;
    SIGVTALRM         = 31;
    SIGWINCH          = 32;
    SIGXCPU           = 33;
    SIGXFSZ           = 34;
    SIGRTMIN          = 35;
    SIGRTMINPLUS1     = 36;
    SIGRTMINPLUS2     = 37;
    SIGRTMINPLUS3     = 38;
    SIGRTMINPLUS4     = 39;
    SIGRTMINPLUS5     = 40;
    SIGRTMINPLUS6     = 41;
    SIGRTMINPLUS7     = 42;
    SIGRTMINPLUS8     = 43;
    SIGRTMINPLUS9     = 44;
    SIGRTMINPLUS10    = 45;
    SIGRTMINPLUS11    = 46;
    SIGRTMINPLUS12    = 47;
    SIGRTMINPLUS13    = 48;
    SIGRTMINPLUS14    = 49;
    SIGRTMINPLUS15    = 50;
    SIGRTMAXMINUS14   = 51;
    SIGRTMAXMINUS13   = 52;
    SIGRTMAXMINUS12   = 53;
    SIGRTMAXMINUS11   = 54;
    SIGRTMAXMINUS10   = 55;
    SIGRTMAXMINUS9    = 56;
    SIGRTMAXMINUS8    = 57;
    SIGRTMAXMINUS7    = 58;
    SIGRTMAXMINUS6    = 59;
